def provide_session(func):
    """
    Decorator that ensures a 'session' argument is available to the wrapped function.
    If the wrapped function declares a parameter named 'session', injects a session
    only if it hasn't been supplied by the caller. If the function does not declare
    a 'session' parameter, a session is still created and passed as a keyword argument.
    """
    from functools import wraps
    import inspect

    @wraps(func)
    def wrapper(*args, **kwargs):
        sig = inspect.signature(func)
